noncompliant:
// Noncompliant - Loading XSLT from untrusted source
XslCompiledTransform xslt = new XslCompiledTransform();
xslt.Load(untrustedXsltPath); // Vulnerable to XSLT injection

// Noncompliant - Enabling scripts in XSLT settings
XsltSettings settings = new XsltSettings();
settings.EnableScript = true;
xslt.Load(xsltPath, settings, new XmlUrlResolver());

compliant:
// Compliant - Using trusted XSLT and disabling dangerous features
XslCompiledTransform xslt = new XslCompiledTransform();
XsltSettings settings = new XsltSettings();
settings.EnableScript = false;
settings.EnableDocumentFunction = false;
xslt.Load(trustedXsltPath, settings, null);

// Compliant - Using embedded resource XSLT
using (Stream xsltStream = Assembly.GetExecutingAssembly().GetManifestResourceStream("App.Transform.xslt"))
{
    xslt.Load(XmlReader.Create(xsltStream));
}
